import './App.css';
import axios from 'axios';
import { useEffect, useState } from 'react';

function App() {
    const [listOfUsers, setListOfUsers] = useState([]);

    useEffect(() => {
        axios.get("http://localhost:3001/users").then((response) => {
            setListOfUsers(response.data);
        })
    }, []);
    return (
        <div className="App">
            {listOfUsers.map((value, key) => {
                return (
                    <div class="mt-6 border-t border-gray-100 box-border size-128 border-2 p-4">
                        <dl class="divide-y divide-gray-100">
                            <div class="px-4 py-6 sm:grid sm:grid-cols-3 sm:gap-4 sm:px-0">
                                <dt className="text-sm/6 font-medium text-gray-900">User</dt>
                                <dd className="mt-1 text-sm/6 text-gray-700 sm:col-span-2 sm:mt-0">{value.username}</dd>
                                <dt className="text-sm/6 font-medium text-gray-900">Email</dt>
                                <dd className="mt-1 text-sm/6 text-gray-700 sm:col-span-2 sm:mt-0">{value.email}</dd>
                            </div>
                        </dl>
                    </div>
                );
            })}
        </div>
    );
}

export default App;
